class Solution:
    def minStable(self, nums: List[int], maxC: int) -> int:
        def gcd(a, b):
            while b:
                a, b = b, a % b
            return a
        n = len(nums)
        res = 0
        for i in range(n):
            cnt = 0
            g = nums[i]
            for j in range(i, n):
                g = gcd(g, nums[j])
                if g >= 2:
                    cnt += 1
                else:
                    break
            res = max(res, cnt)
            if maxC >= cnt:
                res = max(res, cnt + 1)
        return res
```
